from typing import Tuple

class ConstantTime:
    @staticmethod
    def ct_compare(a: bytes, b: bytes) -> bool:
        if len(a) != len(b):
            return False
        result = 0
        for x, y in zip(a, b):
            result |= x ^ y
        return result == 0

    @staticmethod
    def ct_select(cond: bool, a: bytes, b: bytes) -> bytes:
        mask = -int(cond) & 0xFF
        return bytes((av & mask) | (bv & ~mask & 0xFF) for av, bv in zip(a, b))

    @staticmethod
    def ct_is_zero(x: int, num_bits: int = 32) -> bool:
        # Propagate any 1-bit to LSB
        for shift in [1, 2, 4, 8, 16]:
            if shift < num_bits:
                x |= x >> shift
        return (x & 1) == 0

import hashlib
import time
import math
from typing import Dict

class HashBenchmark:
    def __init__(self, iterations: int = 10000):
        self.iterations = iterations

    def benchmark_all(self, data_size: int = 64) -> Dict[str, float]:
        data = bytes(data_size)
        results = {}

        funcs = {
            'sha256': lambda d: hashlib.sha256(d).digest(),
            'sha512': lambda d: hashlib.sha512(d).digest(),
            'sha3_256': lambda d: hashlib.sha3_256(d).digest(),
            'shake256': lambda d: hashlib.shake_256(d).digest(32)
        }

        for name, func in funcs.items():
            start = time.time()
            for _ in range(self.iterations):
                func(data)
            elapsed = time.time() - start
            results[name] = (elapsed / self.iterations) * 1e6

        return results

    def estimate_wots_time(self, n: int, w: int, hash_us: float) -> Dict[str, float]:
        log_w = int(math.log2(w))
        l1 = math.ceil(8 * n / log_w)
        l2 = math.floor(math.log2(l1 * (w - 1)) / log_w) + 1
        l = l1 + l2

        keygen_hashes = l * (w - 1)
        sign_hashes = l * (w - 1) // 2

        return {
            'keygen_ms': keygen_hashes * hash_us / 1000,
            'sign_ms': sign_hashes * hash_us / 1000,
            'chains': l
        }

