import hashlib
from typing import List, Dict, Optional

class CachedMerkleTree:
    def __init__(self, height: int, n: int = 32):
        self.height = height
        self.n = n
        self.cache: Dict[tuple, bytes] = {}
        self.seed: Optional[bytes] = None
        self.cache_hits = 0
        self.cache_misses = 0

    def _hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()[:self.n]

    def initialize(self, seed: bytes):
        self.seed = seed
        self.cache.clear()
        self.cache_hits = 0
        self.cache_misses = 0

    def compute_node(self, level: int, index: int) -> bytes:
        key = (level, index)
        if key in self.cache:
            self.cache_hits += 1
            return self.cache[key]

        self.cache_misses += 1

        if level == 0:
            result = self._hash(self.seed + index.to_bytes(4, 'big'))
        else:
            left = self.compute_node(level - 1, 2 * index)
            right = self.compute_node(level - 1, 2 * index + 1)
            result = self._hash(left + right)

        self.cache[key] = result
        return result

    def compute_auth_path(self, leaf_idx: int) -> List[bytes]:
        path = []
        idx = leaf_idx
        for level in range(self.height):
            sibling_idx = idx ^ 1
            path.append(self.compute_node(level, sibling_idx))
            idx //= 2
        return path

    def cache_stats(self) -> Dict[str, int]:
        return {
            'entries': len(self.cache),
            'hits': self.cache_hits,
            'misses': self.cache_misses,
            'hit_rate': self.cache_hits / max(1, self.cache_hits + self.cache_misses)
        }

