from typing import Dict, List

class ParameterSelector:
    SCHEMES = {
        'XMSS-10': {'sig_kb': 2.5, 'sign_ms': 5, 'stateful': True, 'max_sigs': 1024},
        'LMS-10': {'sig_kb': 1.6, 'sign_ms': 2, 'stateful': True, 'max_sigs': 1024},
        'SPHINCS-128s': {'sig_kb': 7.9, 'sign_ms': 200, 'stateful': False, 'max_sigs': float('inf')},
        'SPHINCS-128f': {'sig_kb': 17.1, 'sign_ms': 20, 'stateful': False, 'max_sigs': float('inf')}
    }

    def recommend(self, max_sig_kb: float = None, max_sign_ms: float = None,
                  stateful_ok: bool = True, min_sigs: int = 1000) -> List[str]:
        suitable = []
        for name, props in self.SCHEMES.items():
            if max_sig_kb and props['sig_kb'] > max_sig_kb:
                continue
            if max_sign_ms and props['sign_ms'] > max_sign_ms:
                continue
            if not stateful_ok and props['stateful']:
                continue
            if props['max_sigs'] < min_sigs:
                continue
            suitable.append(name)
        return suitable

    def compare(self, schemes: List[str]) -> Dict:
        return {name: self.SCHEMES[name] for name in schemes if name in self.SCHEMES}
